async function deepClean() {
  const origin = window.location.origin;

  localStorage.clear();
  sessionStorage.clear();

  const databases = await indexedDB.databases();
  for (const db of databases) {
    if (db.name) indexedDB.deleteDatabase(db.name);
  }

  if ('caches' in window) {
    const cacheKeys = await caches.keys();
    await Promise.all(cacheKeys.map(key => caches.delete(key)));
  }

  console.log('✅ Limpieza completada. Recargando...');
  setTimeout(() => location.reload(), 500);
}

deepClean();

function inspectLocalStorage() {
  const items = [];
  let totalSize = 0;

  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    const value = localStorage.getItem(key);
    const size = new Blob([value]).size;
    totalSize += size;

    items.push({
      key,
      value: value.length > 100 ? value.substring(0, 100) + '...' : value,
      sizeKB: (size / 1024).toFixed(2)
    });
  }

  console.table(items);
  console.log(`📦 Total: ${items.length} items, ${(totalSize / 1024).toFixed(2)} KB`);

  return { items, totalSizeKB: totalSize / 1024 };
}

inspectLocalStorage();

function exportLocalStorage() {
  const data = {};
  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    data[key] = localStorage.getItem(key);
  }

  const json = JSON.stringify(data, null, 2);
  const blob = new Blob([json], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `localstorage-backup-${Date.now()}.json`;
  a.click();
  URL.revokeObjectURL(url);

  console.log(`✅ Exportados ${Object.keys(data).length} items`);
}

exportLocalStorage();

function importLocalStorage() {
  const input = document.createElement('input');
  input.type = 'file';
  input.accept = 'application/json';

  input.onchange = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const text = await file.text();
    const data = JSON.parse(text);

    let count = 0;
    for (const [key, value] of Object.entries(data)) {
      localStorage.setItem(key, value);
      count++;
    }

    console.log(`✅ Importados ${count} items a localStorage`);
    alert(`Importados ${count} items correctamente`);
  };

  input.click();
}

importLocalStorage();

function snapshotCookies() {
  const cookies = document.cookie.split(';').map(c => c.trim());
  const result = cookies.map(cookie => {
    const [name, ...valueParts] = cookie.split('=');
    const value = valueParts.join('=');
    return { name, value: value || '(empty)' };
  });

  console.table(result);
  console.log(`🍪 Total: ${result.length} cookies`);

  return result;
}

snapshotCookies();

function clearSessionCookies() {
  const cookies = document.cookie.split(';');
  let cleared = 0;

  for (const cookie of cookies) {
    const [name] = cookie.trim().split('=');
    document.cookie = `${name}=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;`;
    cleared++;
  }

  console.log(`🍪 Eliminadas ${cleared} cookies de sesión`);
  alert(`Eliminadas ${cleared} cookies`);
}

clearSessionCookies();

function inspectComponentTree() {
  if (!window.ng || !window.ng.getComponent) {
    console.error('❌ Angular DevTools no detectado. Asegúrate de tener Angular en modo desarrollo.');
    return;
  }

  function traverse(element, depth = 0) {
    const component = window.ng.getComponent(element);
    if (component) {
      const indent = '  '.repeat(depth);
      console.log(`${indent}📦 ${component.constructor.name}`, component);
    }

    for (const child of element.children) {
      traverse(child, depth + 1);
    }
  }

  traverse(document.body);
  console.log('✅ Árbol de componentes escaneado');
}

inspectComponentTree();

