async function benchmarkChangeDetection(iterations = 100) {
  if (!window.ng) {
    console.error('❌ Angular no detectado');
    return;
  }

  const appRef = window.ng.getComponent(document.body)?.appRef;
  if (!appRef || !appRef.tick) {
    console.error('❌ No se pudo acceder a ApplicationRef');
    return;
  }

  const times = [];
  for (let i = 0; i < iterations; i++) {
    const start = performance.now();
    appRef.tick();
    times.push(performance.now() - start);
    await new Promise(r => setTimeout(r, 10));
  }

  const avg = times.reduce((a, b) => a + b, 0) / times.length;
  const min = Math.min(...times);
  const max = Math.max(...times);

  console.log(`📊 Benchmark (${iterations} iteraciones):`);
  console.log(`   Promedio: ${avg.toFixed(2)} ms`);
  console.log(`   Mínimo: ${min.toFixed(2)} ms`);
  console.log(`   Máximo: ${max.toFixed(2)} ms`);
}

benchmarkChangeDetection();

