async function checkAuth() {
  if (!window.firebase) {
    console.error('❌ Firebase no detectado');
    return;
  }

  const auth = window.firebase.auth?.() || window.firebase.getAuth?.();
  if (!auth) {
    console.error('❌ Firebase Auth no inicializado');
    return;
  }

  const user = auth.currentUser;
  if (user) {
    console.log('✅ Usuario autenticado:');
    console.log(`   UID: ${user.uid}`);
    console.log(`   Email: ${user.email}`);
    console.log(`   Email verificado: ${user.emailVerified}`);
    console.log(`   Display name: ${user.displayName || 'N/A'}`);

    const token = await user.getIdTokenResult();
    console.log(`   Token expira: ${new Date(token.expirationTime).toLocaleString()}`);
    console.log(`   Claims:`, token.claims);
  } else {
    console.log('🔓 No hay usuario autenticado');
  }
}

checkAuth();

async function refreshToken() {
  if (!window.firebase) {
    console.error('❌ Firebase no detectado');
    return;
  }

  const auth = window.firebase.auth?.() || window.firebase.getAuth?.();
  if (!auth || !auth.currentUser) {
    console.error('❌ No hay usuario autenticado');
    return;
  }

  const token = await auth.currentUser.getIdToken(true);
  const decoded = JSON.parse(atob(token.split('.')[1]));

  console.log('🔄 Token refrescado:');
  console.log(`   Token: ${token.substring(0, 50)}...`);
  console.log(`   Expira: ${new Date(decoded.exp * 1000).toLocaleString()}`);
  console.log(`   Usuario: ${decoded.user_id || decoded.sub}`);

  return token;
}

refreshToken();

