function monitorFirestore() {
  console.log('🔍 Monitor de Firestore activado');
  console.log('Las operaciones se mostrarán en consola');

  let reads = 0, writes = 0;

  const originalLog = console.log;
  console.log = function(...args) {
    if (args[0] && typeof args[0] === 'string') {
      if (args[0].includes('Firestore') || args[0].includes('firestore')) {
        if (args[0].includes('read')) reads++;
        if (args[0].includes('write') || args[0].includes('set') || args[0].includes('update')) writes++;
      }
    }
    originalLog.apply(console, args);
  };

  setInterval(() => {
    console.log(`📊 Firestore stats - Lecturas: ${reads}, Escrituras: ${writes}`);
  }, 10000);
}

monitorFirestore();

