function interceptFetch() {
  const originalFetch = window.fetch;

  window.fetch = async function(...args) {
    const start = performance.now();
    const url = args[0];
    const method = args[1]?.method || 'GET';

    console.log(`🌐 [${method}] ${url} - iniciando...`);

    try {
      const response = await originalFetch.apply(this, args);
      const duration = (performance.now() - start).toFixed(2);

      console.log(`✅ [${method}] ${url} - ${response.status} (${duration}ms)`);
      return response;
    } catch (error) {
      const duration = (performance.now() - start).toFixed(2);
      console.error(`❌ [${method}] ${url} - error (${duration}ms):`, error);
      throw error;
    }
  };

  console.log('✅ Fetch interceptor activado');
}

interceptFetch();

function simulateLatency(delayMs = 2000) {
  const originalFetch = window.fetch;

  window.fetch = async function(...args) {
    console.log(`⏳ Simulando latencia de ${delayMs}ms...`);
    await new Promise(resolve => setTimeout(resolve, delayMs));
    return originalFetch.apply(this, args);
  };

  console.log(`✅ Latencia simulada: ${delayMs}ms`);
}

simulateLatency(parseInt(prompt('Latencia en ms:', '2000')));

function blockDomain(domain = prompt('Dominio a bloquear:', 'analytics.google.com')) {
  if (!domain) return;

  const originalFetch = window.fetch;

  window.fetch = async function(...args) {
    const url = args[0];
    if (url.includes(domain)) {
      console.error(`🚫 Request bloqueada: ${url}`);
      throw new Error(`Dominio bloqueado: ${domain}`);
    }
    return originalFetch.apply(this, args);
  };

  console.log(`✅ Dominio bloqueado: ${domain}`);
}

blockDomain();

function exportRequests() {
  const requests = window._requestLog || [];

  if (requests.length === 0) {
    console.log('No hay requests registradas. Activa el interceptor primero.');
    return;
  }

  const json = JSON.stringify(requests, null, 2);
  const blob = new Blob([json], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `requests-${Date.now()}.json`;
  a.click();
  URL.revokeObjectURL(url);

  console.log(`✅ Exportadas ${requests.length} requests`);
}

if (!window._requestLog) {
  window._requestLog = [];
  const originalFetch = window.fetch;
  window.fetch = async function(...args) {
    const start = performance.now();
    try {
      const response = await originalFetch.apply(this, args);
      window._requestLog.push({
        url: args[0],
        method: args[1]?.method || 'GET',
        status: response.status,
        duration: performance.now() - start,
        timestamp: new Date().toISOString()
      });
      return response;
    } catch (error) {
      window._requestLog.push({
        url: args[0],
        method: args[1]?.method || 'GET',
        error: error.message,
        duration: performance.now() - start,
        timestamp: new Date().toISOString()
      });
      throw error;
    }
  };
  console.log('📝 Logging de requests activado');
}

exportRequests();

