async function checkCacheStatus() {
  const assets = Array.from(document.querySelectorAll('link[rel="stylesheet"], script[src], img[src]'))
    .map(el => el.href || el.src)
    .filter(src => src && src.startsWith(window.location.origin));

  const uniqueAssets = [...new Set(assets)].slice(0, 10);

  for (const url of uniqueAssets) {
    try {
      const response = await fetch(url);
      const cfCache = response.headers.get('CF-Cache-Status');
      console.log(`${cfCache || 'NO-CF'} - ${url}`);
    } catch (e) {
      console.log(`ERROR - ${url}`);
    }
  }
}

