async function healthCheck(endpoints = prompt('URLs separadas por coma:', window.location.origin)) {
  const urls = endpoints.split(',').map(u => u.trim());

  const results = await Promise.all(
    urls.map(async (url) => {
      const start = performance.now();
      try {
        const response = await fetch(url);
        return {
          url,
          status: response.status,
          ok: response.ok,
          latency: (performance.now() - start).toFixed(2) + 'ms'
        };
      } catch (error) {
        return {
          url,
          status: 'ERROR',
          ok: false,
          latency: (performance.now() - start).toFixed(2) + 'ms',
          error: error.message
        };
      }
    })
  );

  console.table(results);
  return results;
}

healthCheck();

