function detectMemoryLeaks() {
  if (!performance.memory) {
    console.warn('⚠️ performance.memory no soportado. Usa Chrome con flag --enable-precise-memory-info');
    return;
  }

  const snapshots = [];
  let lastHeap = performance.memory.usedJSHeapSize;

  const interval = setInterval(() => {
    const current = performance.memory.usedJSHeapSize;
    const growth = (current - lastHeap) / lastHeap * 100;

    snapshots.push({
      time: new Date().toLocaleTimeString(),
      heap: (current / 1048576).toFixed(2) + ' MB',
      growth: growth.toFixed(2) + '%'
    });

    if (growth > 20) {
      console.warn(`⚠️ Posible memory leak: crecimiento del ${growth.toFixed(2)}% en 5s`);
    }

    lastHeap = current;
  }, 5000);

  setTimeout(() => {
    clearInterval(interval);
    console.table(snapshots);
    console.log('✅ Monitoreo finalizado');
  }, 30000);

  console.log('🔍 Monitoreando memory leaks por 30s...');
}

detectMemoryLeaks();

