function highlightAccessibilityIssues() {
  const issues = [];

  document.querySelectorAll('img').forEach(img => {
    if (!img.alt || img.alt === '') {
      img.style.outline = '3px solid red';
      issues.push(`img sin alt: ${img.src}`);
    }
  });

  document.querySelectorAll('button').forEach(btn => {
    if (!btn.textContent.trim() && !btn.getAttribute('aria-label')) {
      btn.style.outline = '3px solid orange';
      issues.push(`botón sin texto ni aria-label`);
    }
  });

  document.querySelectorAll('input').forEach(input => {
    if (!input.id && !input.getAttribute('aria-label')) {
      input.style.outline = '3px solid orange';
      issues.push(`input sin id ni aria-label`);
    }
  });

  console.log(`♿ Problemas de accesibilidad encontrados: ${issues.length}`);
  issues.forEach(i => console.log(`   ${i}`));
}

